suggestion:
根本解决方案：不修改全局 settings.json，而是通过 --settings 参数传递配置文件路径（launchSession 中已有此逻辑）。如果 VSCode 扩展不支持 --settings，则应使用文件锁（proper-lockfile）或队列机制确保串行化。至少应添加一个互斥锁：

var settingsLock = false;
function swapSettingsJson(configFile, callback) {
  if (settingsLock) { /* 等待或拒绝 */ return; }
  settingsLock = true;
  // ... 执行 swap
  // callback 中释放锁
}

